={{ (() => {
  const items = $items('📊 Read Week\'s Analytics') || [];
  const rows = items.map(i => i.json).filter(r => r['Total Views']);

  // Filter to last 7 days
  const cutoff = new Date();
  cutoff.setDate(cutoff.getDate() - 7);
  const weekly = rows.filter(r => new Date(r['Date']) >= cutoff);

  // Sort by Total Views descending
  weekly.sort((a, b) => (parseInt(b['Total Views']) || 0) - (parseInt(a['Total Views']) || 0));

  // Take top 5
  const top5 = weekly.slice(0, 5);
  const totalViews = top5.reduce((sum, r) => sum + (parseInt(r['Total Views']) || 0), 0);

  const videoList = top5.map((r, i) => ({
    rank: i + 1,
    file_code_name: r['File Code Name'],
    views: parseInt(r['Total Views']) || 0,
    tier: r['Tier'],
    top_platform: r['Top Platform']
  }));

  return JSON.stringify({
    week_ending: new Date().toISOString().split('T')[0],
    total_weekly_views: totalViews,
    video_count: top5.length,
    top_5: videoList,
    file_code_names: top5.map(r => r['File Code Name']),
    compilation_ready: top5.length >= 3
  });
})() }}

