parameters.jsonOutput:
={{ (() => {
  const meta = JSON.parse($json.message.content);
  const prev = $('🏆 Get Top 5 of the Week').item.json;

  // Generate FFmpeg concat instructions
  const ffmpegOrder = meta.video_order.map((name, i) => {
    return 'file \'' + name + '.mp4\'';
  }).join('\n');

  // Generate timestamps (assuming ~30s per short)
  const timestamps = meta.video_order.map((name, i) => {
    const mins = Math.floor((i * 30) / 60);
    const secs = (i * 30) % 60;
    return String(mins).padStart(2, '0') + ':' + String(secs).padStart(2, '0') + ' - ' + name.replace(/-/g, ' ');
  }).join('\n');

  return JSON.stringify({
    week_ending: prev.week_ending,
    total_weekly_views: prev.total_weekly_views,
    yt_title: meta.yt_title,
    yt_description: meta.yt_description.replace('TIMESTAMPS', timestamps),
    yt_tags: meta.yt_tags,
    thumbnail_text: meta.thumbnail_text,
    thumbnail_prompt: meta.thumbnail_prompt,
    video_order: meta.video_order,
    transition_style: meta.transition_style,
    intro_text: meta.intro_text,
    ffmpeg_concat_file: ffmpegOrder,
    timestamps: timestamps,
    compilation_filename: 'weekly-compilation-' + prev.week_ending + '.mp4'
  });
})() }}

